howItWorks.step1Code:
yourCenturion.understand({
  mission: 'yours',
  privacy: 'absolute',
  home: 'defined',
  leavesHome: false
})

// Capito e rimane con te.

howItWorks.step2Code:
yourCenturion.place({
  where: 'your home',
  outsideWorld: 'your choice',
  leaves: false
})

// Sistemato. Non esce nulla.

howItWorks.step3Code:
yourCenturion.live({
  always: true,
  learns: 'from you only',
  shares: 'nothing',
  companySees: 'nothing'
})

// Privato. Leale. Il tuo.

developers.code1:
// Le skill di altre persone non sono affidabili
skill.fromSomeoneElse({
  trust: 'none',
  risk: 'stolen secrets | hidden behaviour'
})

// Centurion non installerà
// la skill di un estraneo solo sulla tua parola.

developers.code2:
centurion.makeSkill({
  for: 'what you actually need',
  basedOn: 'your life's mission',
  author: 'your Centurion'
})

// Crea skill. Non va
// a comprarle in un negozio.

developers.code3:
work.continues({
  gap: 'found',
  skill: 'made now',
  stays: 'with you'
})

// Le skill appaiono quando servono —
// e restano a casa tua, sotto il tuo controllo.

developers.code4:
loop.run({
  notice: true,
  act: true,
  learn: true,
  improve: true
})

// Osserva. Agisci. Impara. Migliora.
// Le skill migliorano con l'uso —
// senza inviare dati a casa.

